import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Select, MenuItem } from '@material-ui/core';

export default function FocManagement() {
  const [focs, setFocs] = useState([]);
  const [items, setItems] = useState([]);
  const [newFoc, setNewFoc] = useState({ item: { id: '' }, quantity: 0, reason: '' });

  useEffect(() => {
    axios.get('http://localhost:8080/api/focs').then(res => setFocs(res.data));
    axios.get('http://localhost:8080/api/items').then(res => setItems(res.data));
  }, []);

  const addFoc = () => {
    axios.post('http://localhost:8080/api/focs', newFoc).then(res => {
      setFocs([...focs, res.data]);
      setNewFoc({ item: { id: '' }, quantity: 0, reason: '' });
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <Select
          value={newFoc.item.id}
          onChange={e => setNewFoc({ ...newFoc, item: { id: e.target.value } })}
        >
          {items.map(item => (
            <MenuItem key={item.id} value={item.id}>{item.name}</MenuItem>
          ))}
        </Select>
        <TextField
          label="Quantity"
          type="number"
          value={newFoc.quantity}
          onChange={e => setNewFoc({ ...newFoc, quantity: parseInt(e.target.value) })}
        />
        <TextField
          label="Reason"
          value={newFoc.reason}
          onChange={e => setNewFoc({ ...newFoc, reason: e.target.value })}
        />
        <Button onClick={addFoc} color="primary" variant="contained">Add FOC</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Item</TableCell>
            <TableCell>Quantity</TableCell>
            <TableCell>Reason</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {focs.map(foc => (
            <TableRow key={foc.id}>
              <TableCell>{foc.item.name}</TableCell>
              <TableCell>{foc.quantity}</TableCell>
              <TableCell>{foc.reason}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
